        const int64_t row = idx / d;
        const int64_t col = idx - row * d;
        const float* a = A + row * 16;
        float acc = 0.0f;
#pragma unroll
        for (int k = 0; k < 16; ++k) {
            acc = fmaf(a[k], T[static_cast<int64_t>(k) * d + col], acc);
        }
